+    fn fix_args_clone() {
+        let args = FixArgs {
+            manifest_path: PathBuf::from("clone.toml"),
+            check: true,
+            write: false,
+            json: true,
+        };
+        let cloned = args.clone();
+        assert_eq!(cloned.manifest_path, PathBuf::from("clone.toml"));
+        assert!(cloned.check);
+        assert!(!cloned.write);
+        assert!(cloned.json);
+    }
