+        let decision = Ok(fcp_sandbox::EgressDecision {
+            allowed: true,
+            canonical_host: "api.example.com".to_string(),
+            resolved_ips: vec![],
+            port: 443,
+            tls_required: true,
+            expected_sni: Some("api.example.com".to_string()),
+            spki_pins: vec![],
